#include<bits/stdc++.h>
using namespace std;

const int N = 100 + 5;

int f[N][N];

int main()
{
    int n, m;
    cin >> n >> m;
    memset(f, 0x3f, sizeof f);
    for(int i = 1; i <= m; i++)
    {
        int u, v, w;
        cin >> u >> v >> w;
        f[u][v] = f[v][u] = min(f[u][v], w);
    }
    for(int i = 1; i <= n; i++)
        f[i][i] = 0;
    for(int k = 1; k <= n; k++)
        for(int x = 1; x <= n; x++)
            for(int y = 1; y <= n; y++)
                f[x][y] = min(f[x][y], f[x][k] + f[k][y]);
    for(int i = 1; i <= n; i++)
    {
        for(int j = 1; j <= n; j++)
            cout << f[i][j] << ' ';
        cout << '\n';
    }
}
